// ===== KONSTANTA KUNCI STORAGE =====
const STORAGE_KEY = 'niura_articles';

// ===== MUAT DATA DARI STORAGE =====
// Dipanggil sekali saat aplikasi pertama dijalankan
function loadFromStorage() {
  const raw = localStorage.getItem(STORAGE_KEY);
  return raw ? JSON.parse(raw) : []; // Jika kosong, mulai dengan array kosong
}

// ===== SIMPAN DATA KE STORAGE =====
// Dipanggil setiap kali array berubah
function saveToStorage() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(articles));
}

// ===== INISIALISASI — MUAT SAAT STARTUP =====
let articles = loadFromStorage();
renderTable(); // Tampilkan data yang sudah ada

// ===== UPDATE SEMUA FUNGSI CRUD =====

// Tambah artikel
articleForm.addEventListener('submit', e => {
  e.preventDefault();
  const title   = inputTitle.value.trim();
  const content = inputContent.value.trim();
  if (!title || !content) { showToast('Isi semua field!', 'error'); return; }

  articles.push({
    id: Date.now(), title, content,
    createdAt: new Date().toLocaleDateString('id-ID')
  });

  saveToStorage(); // ← TAMBAHAN: simpan ke storage
  renderTable();
  clearForm();
  showToast('Artikel disimpan!');
});

// Hapus artikel
function deleteArticle(id) {
  articles = articles.filter(a => a.id !== id);
  saveToStorage(); // ← TAMBAHAN: simpan ke storage
  renderTable();
  showToast('Artikel dihapus!');
}
